// Before: one monolith handling everything
class OrderApp {
    void placeOrder(Order order) {
        inventoryModule.reserveStock(order);
        paymentModule.charge(order);
        orderRepository.save(order);
    }
}

// After: Order service calls Payment service over REST
@Service
class OrderService {
    private final PaymentClient paymentClient; // calls payment-service over HTTP

    void placeOrder(Order order) {
        paymentClient.charge(order.getPaymentDetails());
        orderRepository.save(order);
    }
}

