// order-service — owns its own database, exposes an API, knows nothing of Payment's internals
@RestController
@RequestMapping("/orders")
class OrderController {

    private final OrderService orderService;

    @PostMapping
    OrderResponse create(@RequestBody OrderRequest request) {
        return orderService.placeOrder(request); // delegates to payment-service via API call
    }
}

