@Retry(name = "gatewayService")
@TimeLimiter(name = "gatewayService")
@Bulkhead(name = "gatewayService", type = Bulkhead.Type.THREADPOOL)
@CircuitBreaker(name = "gatewayService", fallbackMethod = "fallback")
CompletableFuture<PaymentResponse> chargeViaGateway(PaymentRequest request) {
    return CompletableFuture.supplyAsync(() -> gatewayClient.charge(request));
}

PaymentResponse fallback(PaymentRequest request, Throwable ex) {
    return PaymentResponse.failed(request.getOrderId(), "gateway_unavailable");
}

